Exit fullscreen mode

With React 19:

const UserProfile = ({ user, theme }) => {
const formattedName = `${user.firstName} ${user.lastName}`.toUpperCase();
const handleClick = () => {
console.log("Clicked:", formattedName);
};
return <Button onClick={handleClick}>{formattedName}</Button>;
};

